import 'dart:convert';

import 'package:flutter/material.dart';
import 'package:package_info_plus/package_info_plus.dart';
import 'package:url_launcher/url_launcher.dart';

import '../common_widgets.dart';
import '../l10n.dart';

class AboutPage extends StatefulWidget {
  const AboutPage({super.key});

  @override
  State<AboutPage> createState() => _AboutPageState();
}

class _AboutPageState extends State<AboutPage> {
  late final Future<PackageInfo> _packageInfoFuture;

  @override
  void initState() {
    super.initState();
    _packageInfoFuture = PackageInfo.fromPlatform();
  }

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<PackageInfo>(
      future: _packageInfoFuture,
      builder: (context, snapshot) {
        final info = snapshot.data;
        final version = info == null
            ? '--'
            : info.buildNumber.isEmpty
            ? info.version
            : '${info.version}+${info.buildNumber}';

        return SubPageScaffold(
          title: context.l10n.aboutTitle,
          children: [
        // App Logo 区
        Container(
          width: double.infinity,
          padding: const EdgeInsets.symmetric(vertical: 32),
          child: Column(
            children: [
              ClipRRect(
                borderRadius: BorderRadius.circular(20),
                child: Image.memory(
                  base64Decode(''),
                  width: 80,
                  height: 80,
                  fit: BoxFit.cover,
                ),
              ),
              const SizedBox(height: 16),
              Text(
                context.l10n.appName,
                style: TextStyle(color: ac(context).primaryText, fontSize: 20, fontWeight: FontWeight.w700),
              ),
              const SizedBox(height: 4),
              Text(
                context.l10n.appVersionLabel(version),
                style: const TextStyle(color: kHint, fontSize: 13),
              ),
            ],
          ),
        ),
        settingCard(context, [
          SettingRow(
            label: context.l10n.versionNumber,
            trailing: Text(version, style: const TextStyle(color: kHint, fontSize: 14)),
            showDivider: true,
          ),
          SettingRow(
            label: context.l10n.developer,
            trailing: Row(mainAxisSize: MainAxisSize.min, children: [
              GestureDetector(
                onTap: () async {
                  final uri = Uri.parse('https://github.com/Shiroko114514');
                  if (await canLaunchUrl(uri)) await launchUrl(uri, mode: LaunchMode.externalApplication);
                },
                child: const Row(mainAxisSize: MainAxisSize.min, children: [
                  Text('Shiroko114514', style: TextStyle(color: kHint, fontSize: 14)),
                  SizedBox(width: 3),
                  Icon(Icons.open_in_new, color: kHint, size: 13),
                ]),
              ),
              const Text('  /  ', style: TextStyle(color: kHint, fontSize: 14)),
              GestureDetector(
                onTap: () async {
                  final uri = Uri.parse('https://github.com/Lucas04-nhr');
                  if (await canLaunchUrl(uri)) await launchUrl(uri, mode: LaunchMode.externalApplication);
                },
                child: const Row(mainAxisSize: MainAxisSize.min, children: [
                  Text('Lucas', style: TextStyle(color: kHint, fontSize: 14)),
                  SizedBox(width: 3),
                  Icon(Icons.open_in_new, color: kHint, size: 13),
                ]),
              ),
            ]),
            showDivider: true,
          ),
          SettingRow(
            label: context.l10n.openSourceLicense,
            trailing: Text('GPLv3 License', style: TextStyle(color: kHint, fontSize: 14)),
            showDivider: true,
          ),
          SettingRow(
            label: context.l10n.checkUpdate,
            showDivider: false,
            trailing: Text(context.l10n.alreadyLatest, style: const TextStyle(color: Color(0xFF4ECDC4), fontSize: 14)),
          ),
        ]),
        const SizedBox(height: 16),
        Center(
          child: Text(
            context.l10n.aboutFooter,
            textAlign: TextAlign.center,
            style: const TextStyle(color: kHint, fontSize: 12, height: 1.8),
          ),
        ),
          ],
        );
      },
    );
  }
}

